// ============================================================
// HydraNet - Individual DMA API Route
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'

// GET /api/dmas/[id] - Get a single DMA
export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params

    const dma = await prisma.dMA.findUnique({
      where: { id },
      include: {
        utility: { select: { id: true, name: true } },
        manager: { select: { id: true, name: true, email: true } },
        _count: { select: { branches: true, reports: true, engineers: true } },
      },
    })

    if (!dma) {
      return NextResponse.json({ error: 'DMA not found' }, { status: 404 })
    }

    const formattedDma = {
      ...dma,
      utilityName: dma.utility.name,
      managerName: dma.manager?.name || 'Unassigned',
      branchesCount: dma._count.branches,
      reportsCount: dma._count.reports,
      engineersCount: dma._count.engineers,
    }

    return NextResponse.json(formattedDma)
  } catch (error) {
    console.error('Error fetching DMA:', error)
    return NextResponse.json({ error: 'Failed to fetch DMA' }, { status: 500 })
  }
}

// PUT /api/dmas/[id] - Update a DMA
export async function PUT(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params
    const data = await request.json()

    // Build update data - only include fields that are provided
    const updateData: Record<string, unknown> = {}
    
    if (data.name !== undefined) updateData.name = data.name
    if (data.description !== undefined) updateData.description = data.description || null
    if (data.utilityId !== undefined) updateData.utilityId = data.utilityId
    if (data.managerId !== undefined) updateData.managerId = data.managerId || null
    if (data.status !== undefined) updateData.status = data.status

    const dma = await prisma.dMA.update({
      where: { id },
      data: updateData,
      include: {
        utility: { select: { id: true, name: true } },
        manager: { select: { id: true, name: true } },
        _count: { select: { branches: true, reports: true, engineers: true } },
      },
    })

    const formattedDma = {
      ...dma,
      utilityName: dma.utility.name,
      managerName: dma.manager?.name || 'Unassigned',
      branchesCount: dma._count.branches,
      reportsCount: dma._count.reports,
      engineersCount: dma._count.engineers,
    }

    return NextResponse.json(formattedDma)
  } catch (error) {
    console.error('Error updating DMA:', error)
    return NextResponse.json({ error: 'Failed to update DMA' }, { status: 500 })
  }
}

// DELETE /api/dmas/[id] - Delete a DMA
export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params

    await prisma.dMA.delete({
      where: { id },
    })

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error('Error deleting DMA:', error)
    return NextResponse.json({ error: 'Failed to delete DMA' }, { status: 500 })
  }
}